import{_ as a,o as i,c as n,ay as t}from"./chunks/framework.-lzFfN-z.js";const c=JSON.parse('{"title":"前端工程化深度指南","description":"","frontmatter":{},"headers":[],"relativePath":"forntEngineering/intro.md","filePath":"forntEngineering/intro.md","lastUpdated":1780479294000}'),o={name:"forntEngineering/intro.md"};function e(l,s,r,p,h,d){return i(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="前端工程化深度指南" tabindex="-1">前端工程化深度指南 <a class="header-anchor" href="#前端工程化深度指南" aria-label="Permalink to &quot;前端工程化深度指南&quot;">​</a></h1><p>前端工程化并不是特指某一项技术，而是一套<strong>系统性的方法论与基础设施</strong>。它的终极目标是：<strong>将前端开发流程从“手工作坊”升级为“具备极高容错率的现代工业流水线”，实现降本、提效、保质量</strong>。</p><h2 id="_1-核心理念与时代演进" tabindex="-1">1. 核心理念与时代演进 <a class="header-anchor" href="#_1-核心理念与时代演进" aria-label="Permalink to &quot;1. 核心理念与时代演进&quot;">​</a></h2><p>在没有工程化的时代，前端开发仅需将 HTML/CSS/JS 文件通过 FTP 拖拽到服务器。而现代前端应用动辄十万、百万行代码，工程化是解决以下痛点的唯一解药：</p><ul><li><strong>架构腐化：</strong> 巨石应用难以维护，全局变量冲突，依赖关系如乱麻。</li><li><strong>低效重复：</strong> 手动压缩图片、代码，手动处理浏览器兼容性前缀（Polyfill）。</li><li><strong>协作混乱：</strong> 团队成员代码风格各异，合并代码时冲突不断，线上事故频发。</li><li><strong>交付盲盒：</strong> 缺少自动化测试与标准化的 CI/CD 流程，每一次发布都像“开盲盒”。</li></ul><h2 id="_2-工程化的六大核心支柱" tabindex="-1">2. 工程化的六大核心支柱 <a class="header-anchor" href="#_2-工程化的六大核心支柱" aria-label="Permalink to &quot;2. 工程化的六大核心支柱&quot;">​</a></h2><p>随着业务复杂度的爆发，现代工程化不仅关注单体应用，更将视角拉高到了“跨域协同”与“基建复用”的层面。这六大支柱构成了一个完整的企业级前端基建蓝图：</p><h3 id="_2-1-物理与逻辑模块化-modularization" tabindex="-1">2.1 物理与逻辑模块化 (Modularization) <a class="header-anchor" href="#_2-1-物理与逻辑模块化-modularization" aria-label="Permalink to &quot;2.1 物理与逻辑模块化 (Modularization)&quot;">​</a></h3><blockquote><p>如果把系统比作一栋高楼，模块化就是标准化的预制板，核心目的是<strong>高内聚、低耦合</strong>。</p></blockquote><ul><li><strong>JS/TS 逻辑模块化：</strong> 全面拥抱 ES Modules (ESM)。优秀的框架源码往往将模块化做到极致——例如 Vue 3 的源码就将响应式系统独立剥离，你可以脱离视图层单独引入 <code>reactive</code> 或 <code>effect.ts</code> 供其他逻辑使用。</li><li><strong>视图组件化：</strong> 将 HTML/CSS/JS 封装为独立的 UI 组件。</li><li><strong>样式模块化：</strong> 采用 CSS Modules 或原子化 CSS（如 Tailwind CSS）实现样式的作用域绝对隔离。</li><li><strong>微前端架构：</strong> 当银行业务等超大型单页应用（SPA）膨胀到极限，按业务域拆分为多个微应用，实现独立开发、独立部署。</li></ul><h3 id="_2-2-仓库级架构编排-monorepo-architecture-🌟" tabindex="-1">2.2 仓库级架构编排 (Monorepo Architecture) 🌟 <a class="header-anchor" href="#_2-2-仓库级架构编排-monorepo-architecture-🌟" aria-label="Permalink to &quot;2.2 仓库级架构编排 (Monorepo Architecture) 🌟&quot;">​</a></h3><blockquote><p>现代大厂核心基建，解决<strong>跨界复用</strong>与<strong>版本割裂</strong>的心智负担。</p></blockquote><ul><li><strong>单一事实来源：</strong> 摒弃传统的多仓库（Multirepo），将业务线（Apps）、组件库（Packages）、文档站统一收拢在一个 Git 仓库内。</li><li><strong>极速代码共享：</strong> 借助 <code>pnpm workspace</code>，底层组件库的代码一经修改，上层依赖它的所有业务系统（如 <code>basicSOP</code>）立刻热更新，彻底告别繁琐的手动发版联调。</li></ul><h3 id="_2-3-规范化-standardization" tabindex="-1">2.3 规范化 (Standardization) <a class="header-anchor" href="#_2-3-规范化-standardization" aria-label="Permalink to &quot;2.3 规范化 (Standardization)&quot;">​</a></h3><blockquote><p>规范化的终极奥义是 <strong>“用机器代替人治，用工程学战胜人性的惰性”</strong>。</p></blockquote><ul><li><strong>类型契约：</strong> 全面落地 TypeScript，在编译期物理拦截超过 70% 的低级运行时错误。</li><li><strong>逻辑与风格审查：</strong> 使用 ESLint 捕获逻辑坏味道，Prettier 施行“审美独裁”，终结关于代码格式的无意义争论。</li><li><strong>提交防线：</strong> 利用 Husky 劫持 Git Hooks（如 <code>pre-commit</code>），任何不符合规范的代码连本地 commit 都无法生成。</li></ul><h3 id="_2-4-自动化-automation" tabindex="-1">2.4 自动化 (Automation) <a class="header-anchor" href="#_2-4-自动化-automation" aria-label="Permalink to &quot;2.4 自动化 (Automation)&quot;">​</a></h3><blockquote><p>工程师最宝贵的资源是注意力，自动化旨在<strong>消灭所有重复性的人工操作</strong>。</p></blockquote><ul><li><strong>代码生成：</strong> 通过定制 CLI 工具一键生成带有标准目录、基础代码和单元测试的组件脚手架。</li><li><strong>自动化测试：</strong> 结合 Vitest 进行高覆盖率单元测试。特别是在重构复杂底层逻辑（如推演复现 Vue 3 的 <code>watch</code> 调度机制或快速 Diff 算法时），自动化测试是保证不引入新 Bug 的唯一防线。</li></ul><h3 id="_2-5-流程化-workflow-ci-cd" tabindex="-1">2.5 流程化 (Workflow &amp; CI/CD) <a class="header-anchor" href="#_2-5-流程化-workflow-ci-cd" aria-label="Permalink to &quot;2.5 流程化 (Workflow &amp; CI/CD)&quot;">​</a></h3><blockquote><p>将开发完成的代码安全、稳定、可预期地送到线上。</p></blockquote><ul><li><strong>CI (持续集成)：</strong> 代码 Push 后，云端自动拉起干净容器执行依赖安装、Lint 检查和单元测试，这是合并到主干前的“安检机”。</li><li><strong>CD (持续交付) 与语义化发布：</strong> 结合 Changesets 等工具，自动计算 SemVer 版本号、生成 Changelog，并自动化推送到私有 npm 源与生产环境容器。</li></ul><h3 id="_2-6-质量监控与研发效能-monitoring-devops" tabindex="-1">2.6 质量监控与研发效能 (Monitoring &amp; DevOps) <a class="header-anchor" href="#_2-6-质量监控与研发效能-monitoring-devops" aria-label="Permalink to &quot;2.6 质量监控与研发效能 (Monitoring &amp; DevOps)&quot;">​</a></h3><blockquote><p>项目上线不是终点，而是生命周期的后半场。</p></blockquote><ul><li><strong>线上异常追踪：</strong> 接入 Sentry 等监控 SDK，结合 SourceMap 直接反解出线上报错发生在你源码的哪一行。</li><li><strong>性能监控：</strong> 实时采集关键渲染指标，在流水线中加入 Lighthouse 跑分，一旦发现构建体积骤增直接拦截部署。</li></ul><h2 id="_3-深入工程化核心支柱底层" tabindex="-1">3. 深入工程化核心支柱底层 <a class="header-anchor" href="#_3-深入工程化核心支柱底层" aria-label="Permalink to &quot;3. 深入工程化核心支柱底层&quot;">​</a></h2><h3 id="_3-1-物理与逻辑的拆分-从代码行到子应用" tabindex="-1">3.1 物理与逻辑的拆分：从代码行到子应用 <a class="header-anchor" href="#_3-1-物理与逻辑的拆分-从代码行到子应用" aria-label="Permalink to &quot;3.1 物理与逻辑的拆分：从代码行到子应用&quot;">​</a></h3><p>这是工程化的基石。按照从微观到宏观的维度，系统的拆分经历了四个阶段：</p><ul><li><strong>JS 模块化 (文件级)：</strong> 从早期的 IIFE 闭包、CommonJS，演进到当今绝对标准的 <strong>ES Modules (ESM)</strong>。ESM 实现了静态分析，是现代打包工具进行 Tree-shaking（死代码消除）的先决条件。</li><li><strong>CSS 模块化 (样式级)：</strong> 解决全局作用域污染。方案包括 BEM 命名法、CSS Modules、CSS-in-JS，以及当前大火的<strong>原子化 CSS</strong>。</li><li><strong>UI 组件化 (视图级)：</strong> 借助 Vue 3 / React 等框架，将 HTML/CSS/JS 封装为高内聚、低耦合的独立单元，并进一步抽象出跨业务线的<strong>企业级组件库</strong>。</li><li><strong>微前端架构 (应用级)：</strong> 当 SPA 膨胀到极限，通过 qiankun、无界或 Module Federation（模块联邦），将巨石应用拆分为多个独立开发、独立部署的子应用。</li></ul><h3 id="_3-2-规范化-团队协作的钢铁纪律" tabindex="-1">3.2 规范化：团队协作的钢铁纪律 <a class="header-anchor" href="#_3-2-规范化-团队协作的钢铁纪律" aria-label="Permalink to &quot;3.2 规范化：团队协作的钢铁纪律&quot;">​</a></h3><p>规范化旨在利用工具链抹平个体差异，让百人团队的代码看起来像一个人写的。</p><ul><li><p><strong>代码质量与类型安全：</strong></p><ul><li><strong>ESLint：</strong> 作为“逻辑警察”，排查未定义变量、潜在内存泄漏及强制最佳实践。</li><li><strong>TypeScript：</strong> 将弱类型语言升级为强类型，在编译期物理拦截 70% 以上的运行时 <code>undefined</code> 错误，是大型业务重构的定海神针。</li></ul></li><li><p><strong>代码格式独裁 (Prettier)：</strong></p><ul><li>只关注排版（缩进、引号、逗号）。彻底终结团队内“Tabs vs Spaces”的无意义争论。</li></ul></li><li><p><strong>提交规范防线 (Husky + commitlint + lint-staged)：</strong></p><ul><li>拦截不合规的提交信息（必须为 <code>feat/fix/docs</code> 格式）。</li><li>借助 <code>lint-staged</code> 实现按需校验，仅对暂存区（Git Staged）的文件进行 Lint 操作，极大缩短拦截等待时间。</li></ul></li></ul><h3 id="_3-3-自动化与底层引擎-释放极限生产力" tabindex="-1">3.3 自动化与底层引擎：释放极限生产力 <a class="header-anchor" href="#_3-3-自动化与底层引擎-释放极限生产力" aria-label="Permalink to &quot;3.3 自动化与底层引擎：释放极限生产力&quot;">​</a></h3><ul><li><p><strong>现代构建与打包引擎 (Build Tools)：</strong></p><ul><li><strong>Vite：</strong> 现代前端首选。开发环境利用浏览器原生 ESM 特性实现“按需动态编译”，启动速度永远是毫秒级。</li><li><strong>Rspack / Turbopack：</strong> Rust 编写的新生代怪物。赋予老旧 Webpack 巨石应用 10 倍以上的提速。</li><li><strong>tsup / Rollup：</strong> 纯 TS 工具库或 UI 组件库打包的终极武器，提供最纯净的产物和最佳的 Tree-shaking。</li></ul></li><li><p><strong>极速编译器 (Compilers)：</strong></p><ul><li><strong>SWC (Rust) / esbuild (Go)：</strong> 负责将 TS/JSX 瞬间降级转换为浏览器可运行的低版本 JS，彻底取代了缓慢的 Babel。</li></ul></li></ul><h2 id="_4-企业级-monorepo-工程化架构实战" tabindex="-1">4. 企业级 Monorepo 工程化架构实战 <a class="header-anchor" href="#_4-企业级-monorepo-工程化架构实战" aria-label="Permalink to &quot;4. 企业级 Monorepo 工程化架构实战&quot;">​</a></h2><p>在多条业务线并行、且存在大量内部共享基建的场景下，<strong>Monorepo 结合高性能任务编排工具</strong>是目前前端工程化的终极形态。</p><h3 id="_4-1-核心拓扑结构设计" tabindex="-1">4.1 核心拓扑结构设计 <a class="header-anchor" href="#_4-1-核心拓扑结构设计" aria-label="Permalink to &quot;4.1 核心拓扑结构设计&quot;">​</a></h3><p>利用 <code>pnpm workspace</code>，在一个 Git 仓库内将“业务代码”和“底层基建”进行物理隔离与拓扑关联：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CoreFront-EndConcepts/        # 仓库根目录</span></span>
<span class="line"><span>├── applications/             # 业务应用层 (Apps)</span></span>
<span class="line"><span>│   └── basicSOP/             # 具体的业务系统 (Vite + Vue 3)</span></span>
<span class="line"><span>│       ├── package.json</span></span>
<span class="line"><span>│       └── vite.config.ts</span></span>
<span class="line"><span>├── packages/                 # 基础设施层 (Shared Packages)</span></span>
<span class="line"><span>│   ├── eslint-config/        # 团队统一 Lint 规范包</span></span>
<span class="line"><span>│   └── xunbei-vue/           # 团队自研的跨项目 UI 组件库</span></span>
<span class="line"><span>│       ├── package.json</span></span>
<span class="line"><span>│       └── src/</span></span>
<span class="line"><span>├── pnpm-workspace.yaml       # 🌟 声明工作区领地</span></span>
<span class="line"><span>├── package.json              # 锁定 pnpm 版本与全局脚本</span></span>
<span class="line"><span>└── turbo.json                # 🌟 Turborepo 任务编排引擎</span></span></code></pre></div><h3 id="_4-2-彻底告别发包-本地软链魔法" tabindex="-1">4.2 彻底告别发包：本地软链魔法 <a class="header-anchor" href="#_4-2-彻底告别发包-本地软链魔法" aria-label="Permalink to &quot;4.2 彻底告别发包：本地软链魔法&quot;">​</a></h3><p>在 Monorepo 中，只需在 <code>applications/basicSOP/package.json</code> 中配置工作区协议：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;basic-sop&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;dependencies&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;@xunbei-vue/components&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;workspace:*&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><blockquote><p><strong>工程化收益：</strong> 利用 pnpm 的 <code>workspace:*</code> 协议建立了底层物理软链。修改了一行组件源码，上层的业务页面会<strong>瞬间触发 Vite 的 HMR 热更新</strong>。</p></blockquote><h3 id="_4-3-拓扑任务编排引擎-turbo-json" tabindex="-1">4.3 拓扑任务编排引擎 (turbo.json) <a class="header-anchor" href="#_4-3-拓扑任务编排引擎-turbo-json" aria-label="Permalink to &quot;4.3 拓扑任务编排引擎 (turbo.json)&quot;">​</a></h3><p>Turborepo 解决了跨包构建的调度难题，并提供了云级缓存：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://turbo.build/schema.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tasks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;dependsOn&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;inputs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/**/*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vite.config.ts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;outputs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dist/**&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;lint&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;cache&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="_5-进阶全景-构建企业级前端工程化体系" tabindex="-1">5 进阶全景：构建企业级前端工程化体系 <a class="header-anchor" href="#_5-进阶全景-构建企业级前端工程化体系" aria-label="Permalink to &quot;5 进阶全景：构建企业级前端工程化体系&quot;">​</a></h2><p>当团队规模和项目复杂度达到一定量级，特别是服务于对稳定性、数据安全要求极高的核心业务系统时，工程化就不再仅仅是“打包和规范”，而是要上升到“资产管理、质量闭环与效能驱动”的系统工程维度。</p><h3 id="_5-1-资产沉淀-从散落代码到研发物料中心" tabindex="-1">5.1 资产沉淀：从散落代码到研发物料中心 <a class="header-anchor" href="#_5-1-资产沉淀-从散落代码到研发物料中心" aria-label="Permalink to &quot;5.1 资产沉淀：从散落代码到研发物料中心&quot;">​</a></h3><p>企业内部的核心基建必须具备完善的物料管理机制，而非仅仅停留在源码仓库中。</p><ul><li><strong>语义化发版与 Changelog 生成：</strong> 结合 <code>@changesets/cli</code>，根据 Commit 记录自动生成变更日志，并严格遵循 SemVer（Patch/Minor/Major）进行版本升级与 npm 镜像源推送。</li><li><strong>文档即组件：</strong> 借助 VitePress 或 Storybook，将组件库源码与 API 文档、交互示例深度绑定，实现文档站点与组件代码的同步构建与一键部署。</li></ul><h3 id="_5-2-质量生命线-多维自动化测试与监控" tabindex="-1">5.2 质量生命线：多维自动化测试与监控 <a class="header-anchor" href="#_5-2-质量生命线-多维自动化测试与监控" aria-label="Permalink to &quot;5.2 质量生命线：多维自动化测试与监控&quot;">​</a></h3><p>对于高复杂度的业务后台，不能完全依赖人工测试。</p><ul><li><strong>单元与组件测试：</strong> 采用 <strong>Vitest</strong> 结合 <code>@vue/test-utils</code>，对核心的公共 Hooks、工具函数以及底层的状态流转逻辑进行高覆盖率测试。</li><li><strong>异常捕获与性能度量：</strong> 接入 Sentry 等监控 SDK 进行线上错误溯源（SourceMap 反解）；并利用 Lighthouse CI 在流水线中自动输出性能报告，防止 Bundle 体积无序膨胀。</li></ul><h3 id="_5-3-面向未来的演进-ai-驱动的智能化研发" tabindex="-1">5.3 面向未来的演进：AI 驱动的智能化研发 <a class="header-anchor" href="#_5-3-面向未来的演进-ai-驱动的智能化研发" aria-label="Permalink to &quot;5.3 面向未来的演进：AI 驱动的智能化研发&quot;">​</a></h3><p>这是从资深前端迈向 AI 原生架构师的必经之路。</p><ul><li><strong>AI 赋能基建开发：</strong> 在处理复杂的 Bundleless 架构、编写自定义 Vite 插件（如涉及 <code>estree-walker</code> 进行 AST 语法树动态重写）时，通过集成 AI Agent，实现上下文感知的代码生成与重构。</li><li><strong>源码级分析与沉淀：</strong> 利用 AI 辅助深度推演 Vue 3 核心引擎（如 <code>reactive</code> 依赖收集、双端/快速 Diff 算法机制），极大提升技术白皮书和底层架构文档的编写效率。</li><li><strong>智能 Code Review：</strong> 将 AI 接入 CI 流水线，在提交 PR 时，由大模型自动拦截架构坏味道、评估逻辑复杂度。</li></ul><h2 id="_6-常见问题-faq-与高级避坑指南" tabindex="-1">6. 常见问题 (FAQ) 与高级避坑指南 <a class="header-anchor" href="#_6-常见问题-faq-与高级避坑指南" aria-label="Permalink to &quot;6. 常见问题 (FAQ) 与高级避坑指南&quot;">​</a></h2><h3 id="_6-1-为什么现代大厂全面拥抱-monorepo-架构" tabindex="-1">6.1 为什么现代大厂全面拥抱 Monorepo 架构？ <a class="header-anchor" href="#_6-1-为什么现代大厂全面拥抱-monorepo-架构" aria-label="Permalink to &quot;6.1 为什么现代大厂全面拥抱 Monorepo 架构？&quot;">​</a></h3><ul><li><strong>Multirepo 的痛点：</strong> 割裂感。依赖版本极易冲突；跨业务线重构时联调宛如噩梦。</li><li><strong>Monorepo 的降维打击：</strong> 单一事实来源（Single Source of Truth）。整个企业的底层配置全量收敛在一处，配合 Turborepo 实现按需增量构建，极大降低基建维护心智负担。</li></ul><h3 id="_6-2-webpack-和-vite-的底层核心区别与选型" tabindex="-1">6.2 Webpack 和 Vite 的底层核心区别与选型 <a class="header-anchor" href="#_6-2-webpack-和-vite-的底层核心区别与选型" aria-label="Permalink to &quot;6.2 Webpack 和 Vite 的底层核心区别与选型&quot;">​</a></h3><ul><li><strong>Webpack (Bundle-based)：</strong> 先全量打包，后启动。项目越大，冷启动与热更新越慢。</li><li><strong>Vite (Bundleless / ESM-based)：</strong> 按需动态编译。启动时间永远在毫秒级。</li><li><strong>选型建议：</strong> 新 Web 项目闭眼选择 Vite。重度依赖 Webpack 历史生态的老项目重构，请选择 <strong>Rspack</strong> 作为无痛平替。</li></ul><h3 id="_6-3-什么是-幻影依赖-为什么必须用-pnpm" tabindex="-1">6.3 什么是“幻影依赖”，为什么必须用 pnpm？ <a class="header-anchor" href="#_6-3-什么是-幻影依赖-为什么必须用-pnpm" aria-label="Permalink to &quot;6.3 什么是“幻影依赖”，为什么必须用 pnpm？&quot;">​</a></h3><ul><li><strong>产生原因：</strong> npm 和 Yarn 的扁平化机制会将包错误提升至根目录，导致未声明的包能被非法调用。</li><li><strong>pnpm 的物理拦截：</strong> 采用“内容寻址存储 + 硬/软链接”架构，未显式声明的包被物理隔离，彻底扼杀幻影依赖，且极大节省硬盘空间。</li></ul><h3 id="_6-4-prettier-与-eslint-冲突如何解决" tabindex="-1">6.4 Prettier 与 ESLint 冲突如何解决？ <a class="header-anchor" href="#_6-4-prettier-与-eslint-冲突如何解决" aria-label="Permalink to &quot;6.4 Prettier 与 ESLint 冲突如何解决？&quot;">​</a></h3><ul><li><strong>原因：</strong> 早期的 ESLint 既管逻辑，也管“代码长相”，与 Prettier 发生规则冲突。</li><li><strong>解决方案：</strong> 安装 <code>eslint-config-prettier</code> 并在 <code>extends</code> 数组中<strong>置于最后一位</strong>。实现：<strong>ESLint 专抓逻辑 Bug，Prettier 独揽排版大权</strong>。</li></ul><h3 id="_6-5-为什么要强制使用-husky-拦截-git-提交" tabindex="-1">6.5 为什么要强制使用 Husky 拦截 Git 提交？ <a class="header-anchor" href="#_6-5-为什么要强制使用-husky-拦截-git-提交" aria-label="Permalink to &quot;6.5 为什么要强制使用 Husky 拦截 Git 提交？&quot;">​</a></h3><ul><li><strong>铁律：永远不要用管理学去对抗人性的惰性，要用工程学。</strong></li><li>任何低级语法错误或违规的 Commit 描述都会被 Husky 在敲下回车的瞬间物理拦截（Exit Code 1）。这是防止代码库腐化为“屎山”的最后一道防线。</li></ul>`,68)])])}const g=a(o,[["render",e]]);export{c as __pageData,g as default};
